  ('police-8b7f1efc-moex-00419', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '有關我國在人口販運防制之作為，下列敘述何者錯誤？', '["2007年成立跨部會連繫平台，目前平台為防制人口販運及消除種族歧視協調會報", "2009年制定人口販運防制法，立法目的為防制人口販運行為及保護被害人權益", "已連續13年獲得全球人口販運防制成效評比之第1級國家", "工作重點區分為預防、保護、追訴、懲罰4個面向"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "cc74839149f8", "answer_pdf_sha1": "363d3fe37f37", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00420', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '依據最新修正之性侵害犯罪防治法，有關防治性侵害犯罪及保護被害人措施，下列敘述何者正確？', '["醫療機構對被害人診療時，應有社工人員陪同，並應保護被害人之隱私", "處理案件之司法、警察及醫療專責人員，每年至少應接受4小時專業課程", "任何人知有疑似性侵害犯罪情事者，應立即通報，至遲不得超過24小時", "高級中等以下學校每學期應實施至少2小時之性侵害防治教育課程"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "cc74839149f8", "answer_pdf_sha1": "363d3fe37f37", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00421', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '有關警察機關防制跟蹤騷擾之作為，下列敘述何者最為正確？', '["案件受理後，經調查有跟蹤騷擾行為之犯罪嫌疑者，得依職權或被害人請求，核發書面告誡", "案件受理後，應即開始調查、製作書面紀錄，並告知被害人得行使之權利及服務措施", "由警察機關協助被害人向法院聲請保護令，被害人不得自行聲請", "攜帶凶器或其他危險物品實行跟蹤騷擾行為者，屬告訴乃論之罪，警察採不告不理原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "cc74839149f8", "answer_pdf_sha1": "363d3fe37f37", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00422', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '依據最新修正之兒童及少年性剝削防制條例，保護與防制兒童及少年遭受性剝削之作為，下列敘 述何者錯誤？', '["檢察官、司法警察（官）查獲及救援被害人後，應於24小時內將其交由當地直轄市、縣（市） 主管機關", "警察及司法人員於調查、偵查或審判時，詢（訊）問被害人，得通知主管機關指派社工人員陪 同在場", "醫事、社會工作、警察及公寓大廈管理服務等人員，於執行職（業）務知有被害人時，負有通 報義務", "被害人於偵查或審理中受詢（訊）問或詰問時，其法定代理人、醫師、心理師、輔導人員得陪 同在場"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "cc74839149f8", "answer_pdf_sha1": "363d3fe37f37", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
